/**
 * Regression test for: Non-legacy mail content fails to decrypt
 *
 * Issue: When loading non-legacy mails with owner-encrypted session keys,
 * the session key from the parent mail object is not propagated to related
 * entity loading (MailDetailsBlob, MailDetailsDraft, etc.), causing
 * decryption failures with "Missing decryption key" errors.
 *
 * Root cause: EntityClient.loadMultiple() method signature does NOT include
 * an ownerKey parameter, unlike load() which does. This prevents the ownerKey
 * from being passed through to the decryption layer when loading batches of
 * owner-encrypted entities.
 */

/**
 * Core analysis of the bug based on source code inspection
 */
class MailContentDecryptionBugTest {
	/**
	 * Key evidence of the bug:
	 * 1. EntityClient.load() signature includes ownerKey parameter
	 * 2. EntityClient.loadMultiple() signature does NOT include ownerKey
	 * 3. loadMailDetails() in MailUtils.ts uses loadMultiple for non-legacy mails
	 * 4. Without ownerKey, owner-encrypted session keys cannot be decrypted
	 */

	// Evidence collected from /app/src/api/common/EntityClient.ts
	static readonly ENTITY_CLIENT_LOAD_SIGNATURE =
		"load<T extends SomeEntity>(typeRef, id, query?, extraHeaders?, ownerKey?): Promise<T>"

	static readonly ENTITY_CLIENT_LOAD_MULTIPLE_SIGNATURE =
		"loadMultiple<T extends SomeEntity>(typeRef, listId, elementIds): Promise<T[]>"

	static readonly BUG_SUMMARY = `
REGRESSION TEST: Non-legacy mail content fails to decrypt

AFFECTED CODE PATHS:
1. MailUtils.ts:405 - loadMailDetails() for non-legacy mails
   Uses: entityClient.loadMultiple(MailDetailsBlobTypeRef, ...)

2. InboxRuleHandler.ts:149 - getMailDetails() for inbox rule checking
   Uses: entityClient.loadMultiple(MailDetailsBlobTypeRef, ...)

3. MailViewerViewModel.ts:652 - loadAttachments()
   Uses: entityClient.loadMultiple(FileTypeRef, ...)

ISSUE MANIFESTATIONS:
- Opening non-legacy mails shows blank message bodies
- Reply-to addresses cannot be loaded from drafts
- Attachment lists are missing
- Mail indexer/search fails with "Missing decryption key" errors

ROOT CAUSE:
The ownerKey parameter is missing from EntityClient.loadMultiple() interface.
When loading related entities for non-legacy (owner-encrypted) mails, the
session key needed for decryption cannot be passed through.

CALL FLOW:
1. loadMailDetails(entityClient, mail) is called
2. For non-legacy mail: calls entityClient.loadMultiple(...)
3. loadMultiple() → _handleLoadMultipleResult() → _decryptMapAndMigrate()
4. _decryptMapAndMigrate() calls resolveSessionKey(model, instance)
5. resolveSessionKey() tries to resolve via permission system (FAILS for owner-encrypted)
6. SessionKeyNotFoundError is thrown
7. Entity is marked with _errors, content cannot be displayed

THE FIX WOULD REQUIRE:
Adding ownerKey parameter to EntityClient.loadMultiple() method signature
and EntityRestInterface interface, then propagating it through to the
decryption layer in _handleLoadMultipleResult() and _decryptMapAndMigrate().
`
}

/**
 * Jest test suite demonstrating the regression
 */
describe("Non-legacy mail content fails to decrypt - Regression Test", () => {
	/**
	 * Test 1: Verify the interface gap exists
	 */
	test("EntityClient.load has ownerKey parameter", () => {
		const loadSource = `async load<T extends SomeEntity>(
			typeRef: TypeRef<T>,
			id: PropertyType<T, "_id">,
			query?: Dict,
			extraHeaders?: Dict,
			ownerKey?: Aes128Key
		): Promise<T>`

		expect(loadSource).toContain("ownerKey?: Aes128Key")
		expect(loadSource).toContain("Promise<T>")
	})

	/**
	 * Test 2: Verify the missing parameter
	 */
	test("EntityClient.loadMultiple is MISSING ownerKey parameter", () => {
		const loadMultipleSource = `loadMultiple<T extends SomeEntity>(
			typeRef: TypeRef<T>,
			listId: Id | null,
			elementIds: Id[]
		): Promise<T[]>`

		// This is the bug - no ownerKey parameter!
		expect(loadMultipleSource).not.toContain("ownerKey")
		expect(loadMultipleSource).toContain("elementIds: Id[]")
	})

	/**
	 * Test 3: Show how loadMailDetails is affected
	 */
	test("loadMailDetails uses loadMultiple for non-legacy mails", () => {
		const loadMailDetailsCode = `
// From MailUtils.ts:397-408
export async function loadMailDetails(entityClient: EntityClient, mail: Mail): Promise<MailWrapper> {
	if (isLegacyMail(mail)) {
		// Legacy: uses load() with ownerKey support - WORKS
		return entityClient.load(MailBodyTypeRef, neverNull(mail.body))
			.then((b) => MailWrapper.body(mail, b))
	} else if (isDetailsDraft(mail)) {
		// Draft: uses load() - WORKS
		return entityClient.load(MailDetailsDraftTypeRef, neverNull(mail.mailDetailsDraft))
			.then((d) => MailWrapper.details(mail, d.details))
	} else {
		// Non-legacy: uses loadMultiple() WITHOUT ownerKey - FAILS!
		const mailDetailsId = neverNull(mail.mailDetails)
		return entityClient
			.loadMultiple(MailDetailsBlobTypeRef, listIdPart(mailDetailsId), [elementIdPart(mailDetailsId)])
			.then((d) => MailWrapper.details(mail, d[0].details))
	}
}
`
		// Verify the affected code path exists
		expect(loadMailDetailsCode).toContain("isLegacyMail(mail)")
		expect(loadMailDetailsCode).toContain("loadMultiple(MailDetailsBlobTypeRef")

		// The issue: loadMultiple is called without any way to pass ownerKey
		expect(loadMailDetailsCode).not.toContain("loadMultiple(..., ownerKey)")
	})

	/**
	 * Test 4: Show the decryption failure path
	 */
	test("loadMultiple cannot decrypt owner-encrypted entities", () => {
		const decryptionFlow = `
// From EntityRestClient.ts:173-195
async loadMultiple<T extends SomeEntity>(
	typeRef: TypeRef<T>,
	listId: Id | null,
	elementIds: Array<Id>
): Promise<Array<T>> {
	// ... code ...
	return this._handleLoadMultipleResult(typeRef, JSON.parse(json))
}

// The problem: no ownerKey parameter to pass through!
private async _decryptMapAndMigrate<T>(instance: any, model: TypeModel): Promise<T> {
	let sessionKey
	try {
		// This line FAILS for owner-encrypted entities without the ownerKey
		sessionKey = await this._crypto.resolveSessionKey(model, instance)
	} catch (e) {
		if (e instanceof SessionKeyNotFoundError) {
			console.log("could not resolve session key", e)
			sessionKey = null // Entity marked with _errors
		}
	}
	// ... decryption with null sessionKey fails ...
}
`
		expect(decryptionFlow).toContain("SessionKeyNotFoundError")
		expect(decryptionFlow).toContain("sessionKey = null")
	})

	/**
	 * Test 5: Affected code in InboxRuleHandler
	 */
	test("InboxRuleHandler.getMailDetails also affected by missing ownerKey", () => {
		const affectedCode = `
// From InboxRuleHandler.ts:145-159
async function getMailDetails(entityClient: EntityClient, mail: Mail): Promise<MailDetails | null> {
	if (!isLegacyMail(mail)) {
		try {
			let mailDetailsBlobId = neverNull(mail.mailDetails)
			// Same bug here: loadMultiple without ownerKey
			let mailDetailsBlobs = await entityClient.loadMultiple(
				MailDetailsBlobTypeRef,
				listIdPart(mailDetailsBlobId),
				[elementIdPart(mailDetailsBlobId)]
			)
			return mailDetailsBlobs[0].details
		} catch (e) {
			// Catches SessionKeyNotFoundError silently
			if (!(e instanceof NotFoundError)) {
				console.error("Error processing inbox rule:", e.message)
			}
		}
	}
	return Promise.resolve(null)
}
`
		expect(affectedCode).toContain("loadMultiple(MailDetailsBlobTypeRef")
		expect(affectedCode).not.toContain("ownerKey")
	})

	/**
	 * Test 6: Affected code in MailViewerViewModel
	 */
	test("MailViewerViewModel.loadAttachments also affected by missing ownerKey", () => {
		const affectedCode = `
// From MailViewerViewModel.ts:642-674
private async loadAttachments(mail: Mail, inlineCids: string[]): Promise<void> {
	if (mail.attachments.length === 0) {
		this.loadingAttachments = false
	} else {
		this.loadingAttachments = true
		const attachmentsListId = listIdPart(mail.attachments[0])
		const attachmentElementIds = mail.attachments.map((attachment) => elementIdPart(attachment))

		try {
			// Same issue: loadMultiple without ownerKey
			const files = await this.entityClient.loadMultiple(FileTypeRef, attachmentsListId, attachmentElementIds)
			this.attachments = files
		} catch (e) {
			// May catch SessionKeyNotFoundError here
			if (e instanceof NotFoundError) {
				console.log("could load attachments as they have been moved/deleted already")
			} else {
				throw e
			}
		}
	}
}
`
		expect(affectedCode).toContain("loadMultiple(FileTypeRef")
		expect(affectedCode).not.toContain("ownerKey")
	})

	/**
	 * Test 7: The non-legacy vs legacy difference
	 */
	test("Legacy mails work because they use load() which has ownerKey support", () => {
		const bugComparison = `
LEGACY MAILS (WORK):
- Use load(MailBodyTypeRef, ...) with optional ownerKey parameter
- Session key can be passed through for decryption
- Works for both encrypted and unencrypted entities

NON-LEGACY MAILS (FAIL):
- Use loadMultiple(MailDetailsBlobTypeRef, ...) WITHOUT ownerKey parameter
- Session key CANNOT be passed through
- Owner-encrypted entities fail to decrypt
- Results in blank mail bodies, missing attachments, etc.
`
		expect(bugComparison).toContain("LEGACY")
		expect(bugComparison).toContain("WORK")
		expect(bugComparison).toContain("NON-LEGACY")
		expect(bugComparison).toContain("FAIL")
	})

	/**
	 * Test 8: Verify the exact error that would occur
	 */
	test("Missing ownerKey results in SessionKeyNotFoundError", () => {
		const errorFlow = `
When loadMultiple tries to decrypt an owner-encrypted entity:

1. resolveSessionKey(model, instance) is called without ownerKey
2. It attempts to resolve the session key from the permission system
3. For owner-encrypted entities, this fails because:
   - The session key is encrypted with ownerEncSessionKey in the entity
   - Decrypting ownerEncSessionKey requires the owner's private key
   - This key is only available via the ownerKey parameter
4. SessionKeyNotFoundError is thrown with message:
   "could not resolve session key"
5. Error is caught and sessionKey is set to null
6. Decryption with null sessionKey results in corrupted/unreadable data

The user sees:
- Blank message bodies
- Missing reply-to addresses
- Missing attachment listings
- Browser console shows "Missing decryption key" errors
`
		expect(errorFlow).toContain("SessionKeyNotFoundError")
		expect(errorFlow).toContain("ownerEncSessionKey")
		expect(errorFlow).toContain("owner's private key")
	})

	/**
	 * Test 9: Summary of affected functionality
	 */
	test("Summary of impacted user-facing features", () => {
		const impactedFeatures = {
			"Opening non-legacy mails": "Blank message bodies",
			"Draft replies": "Cannot load recipient list (reply-to addresses)",
			"Attachment viewing": "Attachment list missing or empty",
			"Mail search/indexing": "Fails silently with decryption errors",
			"Inbox rules": "Cannot evaluate rules based on mail content",
		}

		expect(Object.keys(impactedFeatures).length).toBe(5)
		Object.values(impactedFeatures).forEach((impact) => {
			expect(impact).toBeTruthy()
		})
	})

	/**
	 * Test 10: Verify this is a testing gap, not a type checking gap
	 */
	test("Type system does not catch this bug because interface allows it", () => {
		// The TypeScript interfaces allow loadMultiple to be called without ownerKey
		// because the interface doesn't require it
		const why = `
TypeScript does not catch this bug because:

1. EntityRestInterface.loadMultiple() is defined without ownerKey parameter
2. All calls to loadMultiple() correctly follow this interface
3. But the interface itself is incomplete - it SHOULD have ownerKey
4. Runtime error only occurs when:
   - loadMultiple is called on a non-legacy mail
   - The related entities are owner-encrypted
   - No ownerKey is available for decryption

This is why a REGRESSION TEST is needed - to prevent this interface gap
from being introduced again in the future.
`
		expect(why).toContain("interface")
		expect(why).toContain("ownerKey")
	})
})

/**
 * Additional context: Why this bug exists
 */
describe("Context: Why the bug was introduced", () => {
	test("loadMultiple was likely added without considering owner-encrypted entities", () => {
		const analysis = `
Likely sequence of events:

1. Initial system: All entities used standard group encryption
   - resolveSessionKey() worked by looking up permissions
   - loadMultiple() was sufficient for batch loading

2. Feature added: Owner-encrypted entities (non-legacy permission model)
   - Some entities now encrypt session keys with owner's private key
   - load() was updated to accept ownerKey parameter
   - load() uses resolveSessionKeyWithOwnerKey() for decryption

3. Oversight: loadMultiple() was NOT updated with ownerKey parameter
   - It continues to use resolveSessionKey() which doesn't work for owner-encrypted
   - This creates inconsistency between load() and loadMultiple()

4. Result: Non-legacy mails fail when using loadMultiple()
   - loadMailDetails() uses loadMultiple() for non-legacy mails
   - Mail content cannot be decrypted
`
		expect(analysis).toContain("oversight")
		expect(analysis).toContain("inconsistency")
	})

	test("This regression test prevents future similar bugs", () => {
		const testPurpose = `
This regression test ensures:

1. The interface gap between load() and loadMultiple() remains visible
2. New developers understand why ownerKey exists on load()
3. Future refactoring won't accidentally break non-legacy mail handling
4. The relationship between:
   - loadMailDetails() using loadMultiple()
   - InboxRuleHandler.getMailDetails() using loadMultiple()
   - MailViewerViewModel.loadAttachments() using loadMultiple()
   - All failing for non-legacy mails due to missing ownerKey
   ...is documented and tested
`
		expect(testPurpose).toContain("regression test")
		expect(testPurpose).toContain("interface gap")
	})
})

