}

function expect(value: any): any {
	return {
		toBeTruthy: () => {
			if (!value) throw new Error(`Expected ${value} to be truthy`)
		},
		toBeFalsy: () => {
			if (value) throw new Error(`Expected ${value} to be falsy`)
		},
		toEqual: (expected: any) => {
			if (value !== expected) throw new Error(`Expected ${value} to equal ${expected}`)
		},
		toContain: (substring: string) => {
			if (typeof value === "string" && !value.includes(substring)) {
				throw new Error(`Expected string to contain "${substring}"`)
			} else if (Array.isArray(value) && !value.includes(substring)) {
				throw new Error(`Expected array to contain "${substring}"`)
			}
		},
		not: {
			toContain: (substring: string) => {
				if (typeof value === "string" && value.includes(substring)) {
					throw new Error(`Expected string NOT to contain "${substring}"`)
				} else if (Array.isArray(value) && value.includes(substring)) {
					throw new Error(`Expected array NOT to contain "${substring}"`)
				}
			},
		},
	}
}

