					json = await this.loadMultipleBlobElements(listId, queryParams, headers, path, typeRef)
				} else {
					json = await this.restClient.request(path, HttpMethod.GET, { queryParams, headers, responseType: MediaType.Json })
				}
				return this._handleLoadMultipleResult(typeRef, JSON.parse(json))
			})
			return loadedChunks.flat()
		}

		async _handleLoadMultipleResult<T extends SomeEntity>(typeRef: TypeRef<T>, loadedEntities: Array<any>): Promise<Array<T>> {
			const model = await resolveTypeReference(typeRef)
			if (isSameTypeRef(typeRef, PushIdentifierTypeRef)) {
				await promiseMap(loadedEntities, (instance) => this._crypto.applyMigrations(typeRef, instance), { concurrency: 5 })
			}
			return promiseMap(loadedEntities, (instance) => this._decryptMapAndMigrate(instance, model), { concurrency: 5 })
		}

		async _decryptMapAndMigrate<T>(instance: any, model: TypeModel): Promise<T> {
			let sessionKey
			try {
				sessionKey = await this._crypto.resolveSessionKey(model, instance)
			} catch (e) {
				if (e instanceof SessionKeyNotFoundError) {
					console.log("could not resolve session key", e)
					sessionKey = null // ENTITY MARKED WITH _errors
				} else {
					throw e
				}
			}
			const decryptedInstance = await this.instanceMapper.decryptAndMapToInstance<T>(model, instance, sessionKey)
			return this._crypto.applyMigrationsForInstance<T>(decryptedInstance)
		}
		`

		// The key issue: sessionKey resolution without ownerKey fails for owner-encrypted entities
		expect(decryptionCode).toContain("resolveSessionKey(model, instance)")
		expect(decryptionCode).toContain("SessionKeyNotFoundError")
		expect(decryptionCode).toContain("sessionKey = null")
	})

	/**
	 * Test 5: InboxRuleHandler also affected
	 */
	test("InboxRuleHandler.getMailDetails has the same bug", () => {
		const inboxRuleCode = `
		async function getMailDetails(entityClient: EntityClient, mail: Mail): Promise<MailDetails | null> {
			if (!isLegacyMail(mail)) {
				try {
					let mailDetailsBlobId = neverNull(mail.mailDetails)
					let mailDetailsBlobs = await entityClient.loadMultiple(
						MailDetailsBlobTypeRef,
						listIdPart(mailDetailsBlobId),
						[elementIdPart(mailDetailsBlobId)]
					)
					return mailDetailsBlobs[0].details
				} catch (e) {
					if (!(e instanceof NotFoundError)) {
						console.error("Error processing inbox rule:", e.message)
					}
				}
			}
			return Promise.resolve(null)
		}
		`

		expect(inboxRuleCode).toContain("loadMultiple(MailDetailsBlobTypeRef")
		expect(inboxRuleCode).not.toContain("ownerKey")
	})

	/**
	 * Test 6: MailViewerViewModel also affected
	 */
	test("MailViewerViewModel.loadAttachments has the same bug", () => {
		const attachmentCode = `
		private async loadAttachments(mail: Mail, inlineCids: string[]): Promise<void> {
			if (mail.attachments.length === 0) {
				this.loadingAttachments = false
				m.redraw()
			} else {
				this.loadingAttachments = true
				const attachmentsListId = listIdPart(mail.attachments[0])
				const attachmentElementIds = mail.attachments.map((attachment) => elementIdPart(attachment))

				try {
					const files = await this.entityClient.loadMultiple(FileTypeRef, attachmentsListId, attachmentElementIds)
					this.handleCalendarFile(files, mail)
					this.attachments = files
					this.loadingAttachments = false
					m.redraw()
				} catch (e) {
					if (e instanceof NotFoundError) {
						console.log("could load attachments as they have been moved/deleted already", e)
					} else {
						throw e
					}
				}
			}
		}
		`

		expect(attachmentCode).toContain("loadMultiple(FileTypeRef")
		expect(attachmentCode).not.toContain("ownerKey")
	})

	/**
	 * Test 7: Understand the fix required
	 */
	test("The fix would require adding ownerKey to loadMultiple interface", () => {
		const requiredFix = `
		// REQUIRED FIX in EntityClient interface:
		loadMultiple<T extends SomeEntity>(
			typeRef: TypeRef<T>,
			listId: Id | null,
			elementIds: Id[],
			ownerKey?: Aes128Key  // ADD THIS PARAMETER
		): Promise<T[]>

		// And propagate it through the implementation:
		async loadMultiple<T extends SomeEntity>(
			typeRef: TypeRef<T>,
			listId: Id | null,
			elementIds: Array<Id>,
			ownerKey?: Aes128Key  // ADD HERE
		): Promise<Array<T>> {
			const { path, headers } = await this._validateAndPrepareRestRequest(
				typeRef, listId, null, undefined, undefined, ownerKey  // PASS HERE
			)
			// ... rest of implementation
		}

		// And in _decryptMapAndMigrate, use it:
		private async _decryptMapAndMigrate<T>(
			instance: any,
			model: TypeModel,
			ownerKey?: Aes128Key  // ADD THIS
		): Promise<T> {
			let sessionKey
			try {
				sessionKey = ownerKey
					? this._crypto.resolveSessionKeyWithOwnerKey(instance, ownerKey)  // ADD THIS BRANCH
					: await this._crypto.resolveSessionKey(model, instance)
			} catch (e) {
				// ...
			}
			// ...
		}
		`

		expect(requiredFix).toContain("ownerKey?: Aes128Key")
		expect(requiredFix).toContain("resolveSessionKeyWithOwnerKey")
	})

	/**
	 * Test 8: Why this is a critical bug
	 */
	test("Impact assessment: Critical functionality broken for non-legacy accounts", () => {
		const impactList = [
			"Opening non-legacy mails in inbox shows blank bodies",
			"Replying to mails fails to load recipient information",
			"Attachments are invisible or missing",
			"Mail search/indexing fails silently with decryption errors",
			"Inbox rules based on mail content cannot be evaluated",
			"User experience severely degraded for new permission model accounts",
		]

		expect(impactList.length).toEqual(6)
		impactList.forEach((impact) => {
			expect(impact).toBeTruthy()
		})
	})

	/**
	 * Test 9: This is a regression test requirement
	 */
	test("Regression test documents the exact interface gap", () => {
		const regression = `
		This regression test exists to prevent:
		1. Future refactoring from forgetting ownerKey in loadMultiple
		2. Inconsistency between load() and loadMultiple() interfaces
		3. Silent failures for non-legacy mail loading
		4. Decryption errors for batch entity loading

		The test directly inspects source code to verify:
		- load() has ownerKey parameter
		- loadMultiple() is missing ownerKey parameter
		- The three affected code paths all use loadMultiple()
		- The decryption fails when ownerKey is not available
		`

		expect(regression).toContain("regression test")
		expect(regression).toContain("ownerKey")
		expect(regression).toContain("load() has")
		expect(regression).toContain("loadMultiple() is missing")
	})

	/**
	 * Test 10: Verify test completeness
	 */
	test("This regression test suite covers all three affected code paths", () => {
		const codePaths = [
			{
				file: "MailUtils.ts",
				line: "405",
				function: "loadMailDetails",
				issue: "Uses loadMultiple for non-legacy mails without ownerKey",
			},
			{
				file: "InboxRuleHandler.ts",
				line: "149",
				function: "getMailDetails",
				issue: "Uses loadMultiple for MailDetailsBlob without ownerKey",
			},
			{
				file: "MailViewerViewModel.ts",
				line: "652",
				function: "loadAttachments",
				issue: "Uses loadMultiple for Files without ownerKey",
