			expect(path.issue).toContain("ownerKey")
		})
	})
})

/**
 * Export test results for verification
 */
export function getTestResults() {
	return testResults
}

/**
 * When run, execute all tests and print results
 */
if (typeof require !== "undefined" && require.main === module) {
	console.log("\n=== Regression Test Results ===\n")

