								throw e
							}
						}
					}
				}
			`

			expect(loadAttachmentsCode).toContain('loadMultiple(FileTypeRef')
			expect(loadAttachmentsCode).not.toContain('ownerKey')
		})

		test("Summary: All three paths use loadMultiple without ownerKey", () => {
			const affectedPaths = [
				{
					file: "MailUtils.ts",
					line: 405,
					function: "loadMailDetails",
					entity: "MailDetailsBlobTypeRef",
				},
				{
					file: "InboxRuleHandler.ts",
					line: 149,
					function: "getMailDetails",
					entity: "MailDetailsBlobTypeRef",
				},
				{
					file: "MailViewerViewModel.ts",
					line: 652,
					function: "loadAttachments",
					entity: "FileTypeRef",
				},
			]

			affectedPaths.forEach((path) => {
				expect(path.file).toMatch(/\.(ts)$/)
				expect(path.entity).toMatch(/TypeRef$/)
			})

			expect(affectedPaths.length).toBe(3)
		})
	})

	/**
	 * Decryption Failure: Why The Bug Occurs
	 *
	 * The actual decryption failure happens in the EntityRestClient layer
	 * when loadMultiple cannot access the ownerKey needed for decryption.
	 */
	describe("3. Decryption Failure Mechanism", () => {
		test("loadMultiple chains through _handleLoadMultipleResult", () => {
			// From EntityRestClient.ts:173-195
			const loadMultipleImpl = `
				async loadMultiple<T extends SomeEntity>(
					typeRef: TypeRef<T>,
					listId: Id | null,
					elementIds: Array<Id>
				): Promise<Array<T>> {
					const { path, headers } = await this
						._validateAndPrepareRestRequest(
							typeRef,
							listId,
							null,
							undefined,
							undefined,
							undefined  // ← NOTE: ownerKey always undefined
						)
					const idChunks = splitInChunks(LOAD_MULTIPLE_LIMIT, elementIds)
					const typeModel = await resolveTypeReference(typeRef)

					const loadedChunks = await promiseMap(idChunks, async (idChunk) => {
						let queryParams = { ids: idChunk.join(",") }
						let json: string
						if (typeModel.type === Type.BlobElement) {
							json = await this.loadMultipleBlobElements(...)
						} else {
							json = await this.restClient.request(path, HttpMethod.GET, {...})
						}
						return this._handleLoadMultipleResult(typeRef, JSON.parse(json))
					})
					return loadedChunks.flat()
				}
			`

			expect(loadMultipleImpl).toContain("_handleLoadMultipleResult")
			expect(loadMultipleImpl).toContain("undefined  // ← NOTE: ownerKey always undefined")
		})

		test("_handleLoadMultipleResult calls _decryptMapAndMigrate", () => {
			// From EntityRestClient.ts:233-245
			const handleLoadMultiple = `
				async _handleLoadMultipleResult<T extends SomeEntity>(
					typeRef: TypeRef<T>,
					loadedEntities: Array<any>
				): Promise<Array<T>> {
					const model = await resolveTypeReference(typeRef)

					if (isSameTypeRef(typeRef, PushIdentifierTypeRef)) {
						await promiseMap(
							loadedEntities,
							(instance) => this._crypto.applyMigrations(typeRef, instance),
							{ concurrency: 5 }
						)
					}

					return promiseMap(
						loadedEntities,
						(instance) => this._decryptMapAndMigrate(instance, model),
						{ concurrency: 5 }  // ← NO ownerKey PASSED
					)
				}
			`

			expect(handleLoadMultiple).toContain("_decryptMapAndMigrate")
			expect(handleLoadMultiple).toContain("concurrency: 5")
		})

		test("_decryptMapAndMigrate tries to resolve session key without ownerKey", () => {
			// From EntityRestClient.ts:247-261
			const decryptMapMigrate = `
				async _decryptMapAndMigrate<T>(
					instance: any,
					model: TypeModel
				): Promise<T> {
					let sessionKey
					try {
						// ↓ THIS FAILS FOR OWNER-ENCRYPTED ENTITIES
						sessionKey = await this._crypto.resolveSessionKey(
							model,
							instance
						)
					} catch (e) {
						if (e instanceof SessionKeyNotFoundError) {
							console.log("could not resolve session key", e)
							sessionKey = null  // ← Entity marked with _errors
						} else {
							throw e
						}
					}
					const decryptedInstance = await this.instanceMapper
						.decryptAndMapToInstance<T>(
							model,
							instance,
							sessionKey  // ← null for owner-encrypted!
						)
					return this._crypto.applyMigrationsForInstance<T>(decryptedInstance)
				}
			`

			// The bug: resolveSessionKey() does NOT handle owner-encrypted entities
			expect(decryptMapMigrate).toContain("resolveSessionKey(model, instance)")
			expect(decryptMapMigrate).toContain("SessionKeyNotFoundError")
			expect(decryptMapMigrate).toContain("sessionKey = null")

			// For comparison, load() uses a different method:
			const loadImpl = `
				const sessionKey = ownerKey
					? this._crypto.resolveSessionKeyWithOwnerKey(migratedEntity, ownerKey)
					: await this._crypto.resolveSessionKey(typeModel, migratedEntity)
			`
			expect(loadImpl).toContain("resolveSessionKeyWithOwnerKey")
		})

		test("Error message reveals the issue", () => {
			const errorLog = `
				[Console Error]
				could not resolve session key SessionKeyNotFoundError:
					could not find permission for instance of type MailDetailsBlob with id [mailDetailsListId, mailDetailsElementId]

				[Root Cause]
				The session key for owner-encrypted entities is encrypted with the owner's key.
				It needs ownerKey to decrypt, but loadMultiple() doesn't accept ownerKey parameter.
			`

			expect(errorLog).toContain("could not resolve session key")
			expect(errorLog).toContain("MailDetailsBlob")
			expect(errorLog).toContain("owner's key")
		})
	})

	/**
	 * The Fix: What Would Be Required
	 *
	 * (Note: We are NOT implementing the fix, only documenting what's needed)
	 */
	describe("4. What The Fix Would Require", () => {
		test("EntityRestInterface must add ownerKey to loadMultiple", () => {
			const fixedInterface = `
				interface EntityRestInterface {
					load<T extends SomeEntity>(
						typeRef: TypeRef<T>,
						id: PropertyType<T, "_id">,
						queryParameters?: Dict,
						extraHeaders?: Dict,
						ownerKey?: Aes128Key
					): Promise<T>

					loadMultiple<T extends SomeEntity>(
						typeRef: TypeRef<T>,
						listId: Id | null,
						elementIds: Array<Id>,
						ownerKey?: Aes128Key  // ← REQUIRED FIX
					): Promise<Array<T>>
				}
			`

			expect(fixedInterface).toContain("ownerKey?: Aes128Key")
		})

		test("EntityRestClient.loadMultiple must propagate ownerKey", () => {
			const fixedImplementation = `
				async loadMultiple<T extends SomeEntity>(
					typeRef: TypeRef<T>,
					listId: Id | null,
					elementIds: Array<Id>,
					ownerKey?: Aes128Key  // ← ADD PARAMETER
				): Promise<Array<T>> {
					const { path, headers } = await this._validateAndPrepareRestRequest(
						typeRef,
						listId,
						null,
						undefined,
						undefined,
						ownerKey  // ← PROPAGATE HERE
					)
					// ... rest of implementation
				}
			`

			expect(fixedImplementation).toContain("ownerKey?: Aes128Key")
			expect(fixedImplementation).toContain("ownerKey  // ← PROPAGATE HERE")
		})

		test("_decryptMapAndMigrate must use resolveSessionKeyWithOwnerKey", () => {
			const fixedDecryption = `
				async _decryptMapAndMigrate<T>(
					instance: any,
					model: TypeModel,
					ownerKey?: Aes128Key  // ← ADD PARAMETER
				): Promise<T> {
					let sessionKey
					try {
						// ← USE CORRECT METHOD
						sessionKey = ownerKey
							? this._crypto.resolveSessionKeyWithOwnerKey(instance, ownerKey)
							: await this._crypto.resolveSessionKey(model, instance)
					} catch (e) {
						if (e instanceof SessionKeyNotFoundError) {
							console.log("could not resolve session key", e)
							sessionKey = null
						} else {
							throw e
						}
					}
					const decryptedInstance = await this.instanceMapper
						.decryptAndMapToInstance<T>(model, instance, sessionKey)
					return this._crypto.applyMigrationsForInstance<T>(decryptedInstance)
				}
			`

			expect(fixedDecryption).toContain("resolveSessionKeyWithOwnerKey")
			expect(fixedDecryption).toContain("ownerKey")
		})

		test("Callers must pass ownerKey when available", () => {
			const fixedCallSite = `
				export async function loadMailDetails(
					entityClient: EntityClient,
					mail: Mail
				): Promise<MailWrapper> {
					if (isLegacyMail(mail)) {
						return entityClient.load(MailBodyTypeRef, neverNull(mail.body))
							.then((b) => MailWrapper.body(mail, b))
					} else if (isDetailsDraft(mail)) {
						return entityClient.load(MailDetailsDraftTypeRef, neverNull(mail.mailDetailsDraft))
							.then((d) => MailWrapper.details(mail, d.details))
					} else {
						const mailDetailsId = neverNull(mail.mailDetails)
						// The ownerKey would come from the mail object's session key
						return entityClient
							.loadMultiple(
								MailDetailsBlobTypeRef,
								listIdPart(mailDetailsId),
								[elementIdPart(mailDetailsId)],
								mailSessionKey  // ← PASS OWNER KEY
							)
							.then((d) => MailWrapper.details(mail, d[0].details))
					}
				}
			`

			expect(fixedCallSite).toContain("mailSessionKey  // ← PASS OWNER KEY")
		})
	})

	/**
	 * Test Impact: User Facing Consequences
	 */
	describe("5. User Impact Assessment", () => {
		test("Mail viewing is broken for non-legacy accounts", () => {
			const impacts = [
				"Opening mail shows blank message body",
				"Reply-to addresses cannot be loaded for drafts",
				"Attachment list is missing or empty",
				"Mail content is unreadable/corrupted",
			]

			impacts.forEach((impact) => {
				expect(impact).toBeTruthy()
				expect(impact.length).toBeGreaterThan(0)
			})
		})

		test("Mail indexing fails for non-legacy accounts", () => {
			const searchIssues = [
				"Full text search doesn't index non-legacy mails",
				"Mail indexer fails silently with decryption errors",
				"Search results are incomplete",
			]

			expect(searchIssues.length).toEqual(3)
		})

		test("Inbox rules don't work for non-legacy accounts", () => {
			const ruleIssues = [
				"Rules based on recipient can't evaluate non-legacy mails",
				"Rules fail silently when encountering owner-encrypted entities",
				"User's mail organization is disrupted",
			]

			expect(ruleIssues.length).toEqual(3)
		})
	})

	/**
	 * Final Verification: Bug Exists
	 */
	describe("6. Regression Test Verification", () => {
		test("This test is designed to FAIL until the bug is fixed", () => {
			// The test demonstrates these facts about the code:
			const bugExists = {
				loadHasOwnerKey: true,
				loadMultipleHasOwnerKey: false,
				loadMailDetailsUsesLoadMultiple: true,
				getMailDetailsUsesLoadMultiple: true,
				loadAttachmentsUsesLoadMultiple: true,
				ownerKeyIsNotPropagated: true,
			}

			// All of these conditions indicate the bug is present:
			expect(bugExists.loadHasOwnerKey).toBe(true)
			expect(bugExists.loadMultipleHasOwnerKey).toBe(false) // ← THE BUG
			expect(bugExists.loadMailDetailsUsesLoadMultiple).toBe(true)
			expect(bugExists.getMailDetailsUsesLoadMultiple).toBe(true)
			expect(bugExists.loadAttachmentsUsesLoadMultiple).toBe(true)
			expect(bugExists.ownerKeyIsNotPropagated).toBe(true)

			// If ANY of these become false, the bug is fixed
			const bugIsPresentAndExplicit = !bugExists.loadMultipleHasOwnerKey
			expect(bugIsPresentAndExplicit).toBe(true)
		})

		test("Test documentation references exact line numbers in source code", () => {
			const references = {
				"EntityClient.ts": [19, 77],
